package com.taskmind.backend.task.interfaces.rest;
import com.taskmind.backend.security.AuthenticatedUserResolver; import com.taskmind.backend.task.application.TaskLinkApplicationService; import com.taskmind.backend.task.domain.model.TaskLink; import com.taskmind.backend.task.interfaces.rest.dto.CreateTaskLinkRequest; import jakarta.validation.Valid; import java.util.*; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/v1/tasks/{taskId}/links") public class TaskLinkController{private final TaskLinkApplicationService service;private final AuthenticatedUserResolver users;public TaskLinkController(TaskLinkApplicationService s,AuthenticatedUserResolver u){service=s;users=u;}@GetMapping public List<TaskLink> list(@PathVariable UUID taskId,@RequestHeader(value="X-User-Id",required=false)UUID id,@RequestHeader(value="X-User-Roles",required=false)String roles,Authentication auth){return service.list(users.resolve(auth,id,roles),taskId);}@PostMapping public ResponseEntity<TaskLink> create(@PathVariable UUID taskId,@RequestHeader(value="X-User-Id",required=false)UUID id,@RequestHeader(value="X-User-Roles",required=false)String roles,Authentication auth,@Valid @RequestBody CreateTaskLinkRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(users.resolve(auth,id,roles),taskId,r.targetTaskId(),r.linkType()));}}
